<?php $__env->startSection('content'); ?><form class="card mx-auto max-w-3xl" method="post" enctype="multipart/form-data" action="<?php echo e($campaign->exists ? route('fundraiser.campaigns.update',$campaign) : route('fundraiser.campaigns.store')); ?>"><?php echo csrf_field(); ?> <?php if($campaign->exists): ?> <?php echo method_field('put'); ?> <?php endif; ?><h1 class="text-2xl font-bold"><?php echo e($campaign->exists ? 'Edit' : 'Buat'); ?> Campaign</h1><select class="input" name="category_id"><?php $__currentLoopData = $categories; $__env->addLoop($__currentLoopData); foreach($__currentLoopData as $category): $__env->incrementLoopIndices(); $loop = $__env->getLastLoop(); ?><option value="<?php echo e($category->id); ?>" <?php if(old('category_id',$campaign->category_id)==$category->id): echo 'selected'; endif; ?>><?php echo e($category->name); ?></option><?php endforeach; $__env->popLoop(); $loop = $__env->getLastLoop(); ?></select><input class="input" name="title" value="<?php echo e(old('title',$campaign->title)); ?>" placeholder="Judul"><textarea class="input" name="short_description" placeholder="Deskripsi singkat"><?php echo e(old('short_description',$campaign->short_description)); ?></textarea><textarea class="input" rows="8" name="story" placeholder="Cerita lengkap"><?php echo e(old('story',$campaign->story)); ?></textarea><input class="input" name="target_amount" type="number" value="<?php echo e(old('target_amount',$campaign->target_amount)); ?>" placeholder="Target dana"><input class="input" name="location" value="<?php echo e(old('location',$campaign->location ?: 'Sumatera Selatan')); ?>" placeholder="Lokasi"><div class="grid gap-3 md:grid-cols-2"><input class="input" name="starts_at" type="date" value="<?php echo e(old('starts_at', optional($campaign->starts_at)->format('Y-m-d'))); ?>"><input class="input" name="ends_at" type="date" value="<?php echo e(old('ends_at', optional($campaign->ends_at)->format('Y-m-d'))); ?>"></div><label class="mt-3 block text-sm font-semibold">Thumbnail<input class="input" name="thumbnail" type="file" accept="image/*"></label><label class="mt-3 block text-sm font-semibold">Dokumen pendukung<input class="input" name="supporting_document" type="file" accept="image/*,application/pdf"></label><button class="btn-primary mt-4">Simpan & Ajukan Verifikasi</button><?php if($errors->any()): ?><ul class="mt-3 text-sm text-red-600"><?php $__currentLoopData = $errors->all(); $__env->addLoop($__currentLoopData); foreach($__currentLoopData as $error): $__env->incrementLoopIndices(); $loop = $__env->getLastLoop(); ?><li><?php echo e($error); ?></li><?php endforeach; $__env->popLoop(); $loop = $__env->getLastLoop(); ?></ul><?php endif; ?></form><?php $__env->stopSection(); ?>

